query {
  authors {
    id
    name
    nationality
    birthDate
    biography
    email
  }
}

query AuthorById($id: ID!) {
  authorById(id: $id) {
    id
    name
    nationality
    birthDate
    biography
    email
  }
}

query AuthorsByNationality($nationality: String!) {
  authorsByNationality(nationality: $nationality) {
    id
    name
    nationality
    birthDate
    email
  }
}

query {
  books {
    id
    title
    isbn
    publishYear
    synopsis
    genre
    available
    author {
      id
      name
      nationality
    }
  }
}

query BookById($id: ID!) {
  bookById(id: $id) {
    id
    title
    isbn
    publishYear
    synopsis
    genre
    available
    author {
      id
      name
      nationality
      birthDate
      email
    }
  }
}

query BookByIsbn($isbn: String!) {
  bookByIsbn(isbn: $isbn) {
    id
    title
    isbn
    publishYear
    genre
    available
    author { id name }
  }
}

query BooksByGenre($genre: Genre!) {
